function validatePortMappings(mappings) {
  mappings = mappings.split(',');
  let isValid = true;
  for (let mapping of mappings) {
    let [container, port] = mapping.split(':');
    if (parseInt(port) < 1024 || parseInt(port) > 65535) {
      isValid = false;
      break;
    }
  }
  return isValid;
}
module.exports = { validatePortMappings };

