class Solution:
  def validate_port_mappings(self, mappings: str) -> bool:
    mappings = mappings.split(',');
    isValid = True;
    for mapping in mappings:
      container, port = mapping.split(':');
      if int(port) < 1024 or int(port) > 65535:
        isValid = False;
        break;
    return isValid;

if __name__ == '__main__':
  import sys
  solution = Solution()
  mappings = 'web:8080, db:54321'
  print(solution.validate_port_mappings(mappings))
